import{_ as l,o as t,c as a,ae as e}from"./chunks/framework.CRIdhvba.js";const p=JSON.parse('{"title":"操作系统教程 · 第 1 章 操作系统是什么","description":"","frontmatter":{"title":"操作系统教程 · 第 1 章 操作系统是什么"},"headers":[],"relativePath":"tutorials/os/index.md","filePath":"tutorials/os/index.md"}'),r={name:"tutorials/os/index.md"};function o(n,i,s,d,_,u){return t(),a("div",null,[...i[0]||(i[0]=[e('<h1 id="第-1-章-·-操作系统是什么" tabindex="-1">第 1 章 · 操作系统是什么 <a class="header-anchor" href="#第-1-章-·-操作系统是什么" aria-label="Permalink to &quot;第 1 章 · 操作系统是什么&quot;">​</a></h1><p>操作系统（Operating System，OS）是连接 <strong>硬件</strong> 与 <strong>应用程序</strong> 的核心软件，它负责管理 CPU、内存、硬盘、网络等资源，并向上层提供统一、抽象的接口。</p><h2 id="_1-1-为什么需要操作系统" tabindex="-1">1.1 为什么需要操作系统？ <a class="header-anchor" href="#_1-1-为什么需要操作系统" aria-label="Permalink to &quot;1.1 为什么需要操作系统？&quot;">​</a></h2><p>如果没有操作系统，每个应用程序都需要自己处理：</p><ul><li>如何把程序加载到内存并运行；</li><li>如何与磁盘、网卡、显示器交互；</li><li>如何与其他程序「和平共处」，避免互相覆盖内存。</li></ul><p>这在现代复杂系统中几乎是不可能完成的任务。因此我们需要一个「中间层」来：</p><ul><li>帮我们管理硬件资源；</li><li>为应用提供统一 API；</li><li>提供权限隔离与安全机制。</li></ul><h2 id="_1-2-操作系统的核心职责" tabindex="-1">1.2 操作系统的核心职责 <a class="header-anchor" href="#_1-2-操作系统的核心职责" aria-label="Permalink to &quot;1.2 操作系统的核心职责&quot;">​</a></h2><ul><li><strong>进程与线程管理</strong>：创建、调度、销毁进程/线程，并在它们之间进行上下文切换。</li><li><strong>内存管理</strong>：虚拟内存、分页机制、内存分配与回收，避免不同进程互相干扰。</li><li><strong>文件系统</strong>：以文件/目录的形式组织磁盘数据，提供读写接口和权限控制。</li><li><strong>设备管理与驱动</strong>：屏蔽底层硬件细节，为键盘、鼠标、显示器、网卡等提供统一访问方式。</li><li><strong>安全与权限控制</strong>：用户/组、访问控制列表、系统调用权限等。</li></ul><h2 id="_1-3-本教程的学习路径" tabindex="-1">1.3 本教程的学习路径 <a class="header-anchor" href="#_1-3-本教程的学习路径" aria-label="Permalink to &quot;1.3 本教程的学习路径&quot;">​</a></h2><p>在后续章节中，你将从「进程/线程」开始，逐步学习：</p><ol><li>进程与线程模型；</li><li>内存管理与虚拟地址空间；</li><li>文件系统与 I/O 子系统；</li><li>同步原语与并发控制；</li><li>常见操作系统实现（Linux 为主）的关键设计与实践。</li></ol><p>本教程会尽量结合实际 Linux 命令与代码示例，帮助你把抽象概念落到真实系统行为上。</p>',13)])])}const c=l(r,[["render",o]]);export{p as __pageData,c as default};
